from flask import Flask, request, redirect, url_for, render_template_string
import os
import smtplib
from email.mime.text import MIMEText

app = Flask(__name__)
app.secret_key = 'your_secret_key'

# Dummy database for demonstration purposes
users_db = {
    'user1@example.com': {'mfa_enabled': False}
}

def send_reset_link(email):
    reset_token = os.urandom(24).hex()
    users_db[email]['reset_token'] = reset_token
    reset_url = f"http://localhost:5000/reset-mfa?email={email}&token={reset_token}"
    msg = MIMEText(f"Click the link to reset your MFA: {reset_url}")
    msg['Subject'] = 'Reset Your MFA'
    msg['From'] = 'no-reply@example.com'
    msg['To'] = email
    with smtplib.SMTP('localhost') as server:
        server.send_message(msg)

@app.route('/enable-mfa', methods=['POST'])
def enable_mfa():
    email = request.form['email']
    if email in users_db and not users_db[email]['mfa_enabled']:
        # Simulate MFA setup
        users_db[email]['mfa_enabled'] = True
        return 'MFA enabled successfully!'
    return 'User not found or MFA already enabled.', 400

@app.route('/disable-mfa', methods=['POST'])
def disable_mfa():
    email = request.form['email']
    if email in users_db and users_db[email]['mfa_enabled']:
        # Simulate MFA removal
        users_db[email]['mfa_enabled'] = False
        return 'MFA disabled successfully!'
